// src/pages/AdminCourses.js
import React, { useState, useEffect } from 'react';
import { coursesService } from '../services/courses';
import { adminService } from '../services/admin';

const AdminCourses = () => {
  const [pendingCourses, setPendingCourses] = useState([]);

  useEffect(() => {
    // جب الكورسات المعلقة (غير المعتمدة)
    const fetchPendingCourses = async () => {
      try {
        const allCourses = await coursesService.getAll();
        // فلتر الكورسات اللي مش معتمدة
        const pending = allCourses.results.filter(course => !course.is_approved);
        setPendingCourses(pending);
      } catch (error) {
        console.error('Error fetching courses:', error);
      }
    };
    fetchPendingCourses();
  }, []);

  const handleApprove = async (id) => {
    try {
      await adminService.approveCourse(id);
      // حدّث القائمة بعد الموافقة
      setPendingCourses(prev => prev.filter(course => course.id !== id));
      alert('تمت الموافقة على الكورس!');
    } catch (error) {
      alert('فشل الموافقة');
    }
  };

  const handleReject = async (id) => {
    try {
      await adminService.rejectCourse(id);
      setPendingCourses(prev => prev.filter(course => course.id !== id));
      alert('تم رفض الكورس!');
    } catch (error) {
      alert('فشل الرفض');
    }
  };

  return (
    <div style={{ padding: '20px' }}>
      <h2>Admin Courses</h2>
      {pendingCourses.length === 0 ? (
        <p>No pending courses</p>
      ) : (
        <table style={{ width: '100%', borderCollapse: 'collapse' }}>
          <thead>
            <tr>
              <th>العنوان</th>
              <th>المُدرّس</th>
              <th>الإجراءات</th>
            </tr>
          </thead>
          <tbody>
            {pendingCourses.map(course => (
              <tr key={course.id}>
                <td>{course.title}</td>
                <td>{course.instructor.email}</td>
                <td>
                  <button onClick={() => handleApprove(course.id)} style={{ marginRight: '10px', backgroundColor: '#28a745', color: 'white' }}>
                    Approve
                  </button>
                  <button onClick={() => handleReject(course.id)} style={{ backgroundColor: '#dc3545', color: 'white' }}>
                    Re
                  </button>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      )}
    </div>
  );
};

export default AdminCourses;
